glsl3.vert:
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
precision highp float;
attribute vec3 a_position;
attribute vec4 a_color;
varying vec4 v_color;
#if USE_TEXTURE
attribute vec2 a_uv0;
varying vec2 v_uv0;
#endif
void main () {
  vec4 pos = vec4(a_position, 1);
  #if CC_USE_MODEL
  pos = cc_matViewProj * cc_matWorld * pos;
  #else
  pos = cc_matViewProj * pos;
  #endif
  #if USE_TEXTURE
  v_uv0 = a_uv0;
  #endif
  v_color = a_color;
  gl_Position = pos;
}

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  uniform a0 {
 float alphaThreshold;
};
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
      if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
      if (alpha < alphaThreshold) discard;
  #endif
}
varying vec4 v_color;
uniform a1 {
 vec4 srcOffset;
};
uniform a2 {
 vec4 maskOffset;
};
#if USE_TEXTURE
varying vec2 v_uv0;
uniform sampler2D texture;
#endif
#if USE_MASK_TEXTURE
uniform sampler2D maskTexture;
#endif
void main () {
  vec4 o = vec4(1, 1, 1, 1);
  #if USE_TEXTURE
  vec4 texture_tmp = texture2D(texture, v_uv0);
  #if CC_USE_ALPHA_ATLAS_texture
      texture_tmp.a *= texture2D(texture, v_uv0 + vec2(0, 0.5)).r;
  #endif
  #if INPUT_IS_GAMMA
    o.rgb *= (texture_tmp.rgb * texture_tmp.rgb);
    o.a *= texture_tmp.a;
  #else
    o *= texture_tmp;
  #endif
  #endif
  #if USE_MASK_TEXTURE
   vec4 a = vec4(1, 1, 1, 1);
   vec2 srcUV = (v_uv0 - vec2(srcOffset.x,srcOffset.y));
   if(srcOffset.y < 0.0){
     srcUV = vec2(v_uv0.y + srcOffset.y,srcOffset.x - v_uv0.x);
   }
   vec2 targetUV = (srcUV*vec2(srcOffset.z,srcOffset.w))/vec2(maskOffset.z,maskOffset.w);
   if(maskOffset.w < 0.0){
     targetUV = vec2(targetUV.y,targetUV.x);
   }
  vec4 maskTexture_tmp = texture2D(maskTexture, vec2(maskOffset.x ,maskOffset.y) + targetUV);
  #if CC_USE_ALPHA_ATLAS_maskTexture
      maskTexture_tmp.a *= texture2D(maskTexture, vec2(maskOffset.x ,maskOffset.y) + targetUV + vec2(0, 0.5)).r;
  #endif
  #if INPUT_IS_GAMMA
    a.rgb *= (maskTexture_tmp.rgb * maskTexture_tmp.rgb);
    a.a *= maskTexture_tmp.a;
  #else
    a *= maskTexture_tmp;
  #endif
    o.a *= a.a;
  #endif
  o *= v_color;
  ALPHA_TEST(o);
  gl_FragColor = o;
}

